mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rno, T.* FROM ( SELECT C.fk_memberid AS memberId, C.company_name AS companyName, C.industry_code AS industryCode, C.addr1 AS addr1, CI.company_type AS companyType, CI.homepage_url AS homepageUrl, TO_CHAR(CI.open_date, 'YYYY') AS foundedYear,
(SELECT I.file_url FROM tbl_image_file I WHERE I.target_type = 'company' AND I.filecategory = 'logo' AND I.target_id = CI.company_intro_id AND ROWNUM = 1 ) AS logoUrl,
(SELECT COUNT(*) FROM tbl_company_follow CF WHERE CF.fk_company_memberid = C.fk_memberid ) AS followerCount,
(SELECT COUNT(*) FROM tbl_job_posting JP WHERE JP.fk_memberid = C.fk_memberid AND JP.status = '게시중' AND JP.is_hidden = 0 AND (JP.deadline_type = 'always' OR JP.deadline_at >= TRUNC(SYSDATE)) ) AS activePostCount
FROM tbl_company C LEFT JOIN tbl_company_intro CI ON C.fk_memberid = CI.fk_memberid JOIN tbl_member M ON C.fk_memberid = M.memberid WHERE M.status = 1 AND C.approved_yn = 1
AND (UPPER(C.company_name) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(C.industry_code) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(DECODE(C.industry_code, 'IT', 'IT·인터넷', 'SW', '소프트웨어', 'FIN', '금융·핀테크', 'EDU', '교육·에듀테크', 'MKT', '마케팅', 'ETC', '기타', C.industry_code)) LIKE '%' || UPPER(#{keyword}) || '%')
AND C.industry_code = #{industry}
AND CI.company_type = #{companyType}
AND (
C.addr1 LIKE '%' || #{ld} || '%'
)
AND (
C.addr1 LIKE '%' || #{loc} || '%'
)
AND EXISTS ( SELECT 1 FROM tbl_job_posting JP2 WHERE JP2.fk_memberid = C.fk_memberid AND JP2.status = '게시중' AND JP2.is_hidden = 0 AND (JP2.deadline_type = 'always' OR JP2.deadline_at >= TRUNC(SYSDATE)) )
ORDER BY C.company_name ASC
ORDER BY activePostCount DESC, C.company_name ASC
ORDER BY followerCount DESC, C.company_name ASC
) T WHERE ROWNUM <= #{endRno} ) WHERE rno >= #{startRno}

SELECT COUNT(*) FROM tbl_company C LEFT JOIN tbl_company_intro CI ON C.fk_memberid = CI.fk_memberid JOIN tbl_member M ON C.fk_memberid = M.memberid WHERE M.status = 1 AND C.approved_yn = 1
AND (UPPER(C.company_name) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(C.industry_code) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(DECODE(C.industry_code, 'IT', 'IT·인터넷', 'SW', '소프트웨어', 'FIN', '금융·핀테크', 'EDU', '교육·에듀테크', 'MKT', '마케팅', 'ETC', '기타', C.industry_code)) LIKE '%' || UPPER(#{keyword}) || '%')
AND C.industry_code = #{industry}
AND CI.company_type = #{companyType}
AND (
C.addr1 LIKE '%' || #{ld} || '%'
)
AND (
C.addr1 LIKE '%' || #{loc} || '%'
)
AND EXISTS ( SELECT 1 FROM tbl_job_posting JP2 WHERE JP2.fk_memberid = C.fk_memberid AND JP2.status = '게시중' AND JP2.is_hidden = 0 AND (JP2.deadline_type = 'always' OR JP2.deadline_at >= TRUNC(SYSDATE)) )

